// LOGIN PAGE
// ═══════════════════════════════════════════════════════════════════════════
test.describe('Login Page', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto(`${BASE_URL}login`);
  });

  test('TC-L01: page title and heading are correct', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await expect(page).toHaveTitle(/EventHub/i);
    await expect(loginPage.pageHeading).toBeVisible();
    await expect(loginPage.subText).toBeVisible();
  });

  test('TC-L02: all form elements are visible', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await expect(loginPage.emailInput).toBeVisible();
    await expect(loginPage.passwordInput).toBeVisible();
    await expect(loginPage.signInButton).toBeVisible();
    await expect(loginPage.registerLink).toBeVisible();
  });

  test('TC-L03: password field masks input', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await loginPage.passwordInput.fill('secret');
    await expect(loginPage.passwordInput).toHaveAttribute('type', 'password');
  });

  test('TC-L04: successful login redirects away from /login', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await loginPage.login(EMAIL, PASSWORD);
    await page.waitForURL(url => !url.pathname.includes('/login'), { timeout: 10_000 });
    expect(page.url()).not.toContain('/login');
  });

  test('TC-L05: logged-in user email appears in navbar', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await loginPage.login(EMAIL, PASSWORD);
    await page.waitForURL(url => !url.pathname.includes('/login'), { timeout: 10_000 });
    await expect(page.getByText(EMAIL)).toBeVisible();
  });

  test('TC-L06: wrong credentials shows error alert', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await loginPage.login('wrong@email.com', 'WrongPass@1');
    await expect(loginPage.errorMessage).toBeVisible({ timeout: 8_000 });
    expect(page.url()).toContain('/login');
  });

  test('TC-L07: Register link navigates to /register', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await loginPage.clickRegister();
    await expect(page).toHaveURL(/\/register/);
  });
});

