// END-TO-END: Book a ticket and verify in My Bookings
// ═══════════════════════════════════════════════════════════════════════════
test.describe('E2E: Book ticket flow', () => {
  test('TC-F01: book World Tech Summit and verify booking appears', async ({ adminPage }) => {
    const bookingsPage = new MyBookingsPage(adminPage);
    const detailPage   = new EventDetailPage(adminPage);

    // Clear any prior bookings for a clean state
    await bookingsPage.goto(BASE_URL);
    await bookingsPage.clearAllBookings();

    // Navigate to event detail and complete booking
    await detailPage.goto(BASE_URL, 1);
    await detailPage.fillBookingForm('Pavan Chaudhari', EMAIL, '+91 9876543210');
    await detailPage.clickConfirmBooking();

    // Should navigate to bookings or show confirmation
    await adminPage.waitForURL(/\/bookings|\/events\/1/, { timeout: 10_000 });

    // Verify booking appears in My Bookings
    await bookingsPage.goto(BASE_URL);
    await expect(bookingsPage.noBookingsHeading).not.toBeVisible({ timeout: 8_000 });
  });
});
